import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { XMarkIcon } from "@heroicons/react/24/solid";
import { motion } from "framer-motion";

export default function EditProfile({ closeModal, onUpdate }) {
  const [user, setUser] = useState(null);
  const [name, setName] = useState("");
  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState("");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [strength, setStrength] = useState(0);

  // 🔥 ROLE DETECTION (Admin / Academic / User)
  const stored = JSON.parse(localStorage.getItem("user") || "{}");
  const role = stored?.role || "USER";

  // 🔥 AUTO API SELECTION
  const getUpdateUrl = () => {
    if (role === "ADMIN") return "http://localhost:8086/user/admin/update-profile";
    if (role === "ACADEMIC") return "http://localhost:8086/user/academic/update-profile";
    return "http://localhost:8086/user/update-profile";
  };

  useEffect(() => {
    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setPreview(res.data.profileImage);
      })
      .catch(() => {
        Swal.fire("Error", "Failed to load profile", "error");
      });
  }, []);

  const calculateStrength = (pwd) => {
    let score = 0;
    if (pwd.length >= 6) score++;
    if (pwd.length >= 10) score++;
    if (/[A-Z]/.test(pwd)) score++;
    if (/[0-9]/.test(pwd)) score++;
    if (/[^A-Za-z0-9]/.test(pwd)) score++;
    setStrength(score);
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);

    const reader = new FileReader();
    reader.onloadend = () => setPreview(reader.result);
    reader.readAsDataURL(file);
  };

  // 🔥 ROLE-BASED UPDATE PROFILE
  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);
      if (imageFile) formData.append("image", imageFile);

      const res = await axios.put(getUpdateUrl(), formData);

      Swal.fire("Success", "Profile updated", "success");

      localStorage.setItem("user", JSON.stringify(res.data));

      onUpdate?.();
      closeModal?.();
    } catch {
      Swal.fire("Error", "Update failed", "error");
    }
  };

  const handleChangePassword = async () => {
    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");
      setCurrentPassword("");
      setNewPassword("");
      setStrength(0);
    } catch {
      Swal.fire("Error", "Password update failed", "error");
    }
  };

  if (!user) {
    return (
      <div className="bg-white p-4 rounded-lg shadow">
        Loading...
      </div>
    );
  }

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-black/40 z-50">

      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="w-[90%] max-w-5xl bg-white rounded-2xl shadow-xl overflow-hidden"
      >

        {/* HEADER */}
        <div className="flex justify-between items-center px-6 py-4 border-b">
          <h2 className="text-lg font-bold">
            Edit Profile ({role})
          </h2>

          <button onClick={closeModal}>
            <XMarkIcon className="w-6 h-6 hover:text-red-500" />
          </button>
        </div>

        {/* BODY */}
        <div className="grid grid-cols-3">

          {/* LEFT */}
          <div className="col-span-1 bg-gray-50 p-6 flex flex-col items-center">

            <img
              src={
                preview ||
                `https://ui-avatars.com/api/?name=${user.username}`
              }
              className="w-24 h-24 rounded-full border-4 border-indigo-500 object-cover"
            />

            <h3 className="mt-3 font-semibold">{user.name}</h3>
            <p className="text-sm text-gray-500">{user.email}</p>

            <label className="mt-4 text-sm text-indigo-600 cursor-pointer">
              Change Photo
              <input type="file" hidden onChange={handleImageChange} />
            </label>

            <button
              onClick={handleUpdateProfile}
              className="mt-6 w-full bg-indigo-600 text-white py-2 rounded-lg"
            >
              Save Profile
            </button>
          </div>

          {/* RIGHT */}
          <div className="col-span-2 p-6 space-y-6">

            <div>
              <label className="text-sm">Full Name</label>
              <input
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full mt-1 p-3 border rounded-lg"
              />
            </div>

            <div className="border-t pt-4">

              <h3 className="font-semibold mb-3">Security</h3>

              <input
                type="password"
                placeholder="Current Password"
                value={currentPassword}
                onChange={(e) => setCurrentPassword(e.target.value)}
                className="w-full mb-3 p-3 border rounded-lg"
              />

              <input
                type="password"
                placeholder="New Password"
                value={newPassword}
                onChange={(e) => {
                  setNewPassword(e.target.value);
                  calculateStrength(e.target.value);
                }}
                className="w-full p-3 border rounded-lg"
              />

              <button
                onClick={handleChangePassword}
                className="mt-4 w-full bg-pink-500 text-white py-2 rounded-lg"
              >
                Update Password
              </button>

            </div>

          </div>
        </div>

      </motion.div>
    </div>
  );
}
